1.2 Filtering

Filter: Count observations (rows) matching a condition


data |&gt; filter(condition) |&gt; nrow()


# Example: data has a type column with only "comment" and "post" values
# How many posts are there in total?

# Method 1: nrow() directly returns the row count; other dplyr functions require pull() to extract the value
data |&gt;
    filter(type == "post") |&gt;
    nrow()

# Method 2:
data |&gt;
    filter(type == "post") |&gt;
    count(type) |&gt;  # swapping count and filter order gives the same result
    pull(n)

# Method 3:
data |&gt;
    filter(type == "post") |&gt;
    summarize(n = n()) |&gt;
    pull(n)

1.3 Most Frequent Category

data |&gt; count(col, sort=T) |&gt; head(1) |&gt; pull(col)


# Example: data has a date column with Date datatype (yyyy-mm-dd)
# Which year had the most posts?

# Method 1:
data |&gt;
    filter(type == "post") |&gt;
    count(year = year(date), sort = TRUE) |&gt;
    head(1) |&gt; # sort=T was specified above, so head(1) works directly
    pull(year)

# Method 2:
data |&gt;
    filter(type == "post") |&gt;
    count(year = year(date)) |&gt; # count produces a two-column df: year and n
    slice_max(n, n = 1) |&gt; # first n is the column name, second is row count — selects the row with max n
    pull(year)

2.1 Rounded Mean or Median

summarize(mean = round(mean(col, na.rm = TRUE), 2)) |&gt; pull(mean)


# Example: mean score of posts in 2019, rounded to 2 decimal places
data |&gt;
    filter(type == "post" & year(date) == 2019) |&gt;
    summarize(mean = round(mean(score, na.rm = TRUE), 2)) |&gt;
    pull(mean)


# Example: median score per year, rounded to 2 decimal places,
# sorted by median score descending, returned as a dataframe
data |&gt;
    filter(type == "post") |&gt;
    group_by(year = year(date)) |&gt;
    summarize(
        median_score = round(median(score, na.rm = TRUE), 2),
        .groups = "drop"  # group + summarize requires .groups = "drop"
    ) |&gt;
    arrange(desc(median_score)) # sort descending; can also write arrange(-median_score)

2.3 Value at Row Maximum

data |&gt;
    slice_max(col1, n = 1) |&gt;
    pull(col2)


# Example: who is the author of the post with the highest word_count?
data |&gt;
    # we want posts only, but data contains other types — filter first
    filter(type == "post") |&gt;
    slice_max(word_count, n = 1) |&gt;
    pull(author)

5.1 Top 5 Keys by Streams
The bar plot below shows the top 5 keys with respect to the streams, where C# appears to be the most popular key, with the highest mean streams (around 600M). E ranks second, followed by D# and A# with similar averages. D has the lowest among the top five. Overall, differences are moderate, suggesting relatively balanced popularity across these keys.


Code
# find keys with top 5 mean stream
top5_key &lt;- df |&gt; 
  group_by(key) |&gt; 
  summarize(mean_streams = mean(streams), .groups = "drop") |&gt; 
  arrange(desc(mean_streams)) |&gt; 
  head(5) |&gt; 
  mutate(key = reorder(key, -mean_streams))  # make key factor




Code
# barplot
plot_ly(
  top5_key, x = ~key, y = ~mean_streams, type = "bar", 
  marker = list(color = "mediumaquamarine")
) |&gt; 
  layout(
    title = list(y = 0.9, text = "Top 5 Popular Keys"),
    xaxis = list(title = "Key", linewidth = 2, range = c(-0.8, 4.8)),
    yaxis = list(title = list(text = "Mean Streams", standoff = 10)),
    margin = list(t = 80, l = 80, r = 20)
  )

1.2 有多少符合条件的 Observation

data |&gt; filter(条件) |&gt; nrow()


# 示例: 已知 data 有 type 列, 其中只有 "comment" 和 "post" 两种值
# 求一共多少个 post

# 方法1: 用 nrow() 直接返回行数, 其他 dplyr 函数都需要最终用 pull() 来取出数值
data |&gt;
    filter(type == "post") |&gt;
    nrow()

# 方法2:
data |&gt;
    filter(type == "post") |&gt;
    count(type) |&gt;  # 此处 count 和 filter 的顺序即使调换结果也一样
    pull(n)

# 方法3:
data |&gt; 
    filter(type == "post") |&gt; 
    summarize(n = n()) |&gt; 
    pull(n)

1.3 某列中 Observation 数量最多的 类 是哪个

data |&gt; count(col, sort=T) |&gt; head(1) |&gt; pull(col)


# 示例: 已知 data 里有 date 列, 其 datatype 是 Date (yyyy-mm-dd)
# 求哪一年的 post 最多

# 方法1:
data |&gt;
    filter(type == "post") |&gt;
    count(year = year(date), sort = TRUE) |&gt;
    head(1) |&gt; # 上一行已经指定了 sort=T, 此处直接用 head(1) 即可
    pull(year)

# 方法2:
data |&gt;
    filter(type == "post") |&gt;
    count(year = year(date)) |&gt; # count 生成一个两列的 df, year 和 n
    slice_max(n, n = 1) |&gt; # 第一个 n 是列名, 第二个是行数, 意为选取n最大的一行
    pull(year)

2.1 求 mean / median 并保留 2 位小数

summarize(mean = round(mean(col, na.rm = TRUE), 2)) |&gt; pull(mean)


# 示例: 求 2019 年 post 的 score 的平均值, 保留 2 位小数
data |&gt;
    filter(type == "post" & year(date) == 2019) |&gt;
    summarize(mean = round(mean(score, na.rm = TRUE), 2)) |&gt;
    pull(mean)


# 示例: 求每年的 post median score, 保留 2 位小数,
# 按 median score 从高到低排列, 展示成一个 dataframe
data |&gt;
    filter(type == "post") |&gt;
    group_by(year = year(date)) |&gt;
    summarize(
        median_score = round(median(score, na.rm = TRUE), 2),
        .groups = "drop"  # group + summarize 必须加上 drop
    ) |&gt;
    arrange(desc(median_score)) # 排序, 也可以写成 arrange(-median_score)

2.3 某列最大值所在行的另一列值

data |&gt; 
    slice_max(col1, n = 1) |&gt; 
    pull(col2)


# 示例: word_count 最多的 post 的 author 是谁?
data |&gt;
    # 问的是 post, 但 data 里不都是 post, 首先要 filter 
    filter(type == "post") |&gt;
    slice_max(word_count, n = 1) |&gt;
    pull(author)

5.1 播放量最高的前五调性
如下条形图所示，在播放量方面，C# 为最受欢迎的调性，平均播放量最高（约 6 亿次）。E 位居第二，D# 与 A# 均值相近紧随其后。D 在前五中最低。总体而言，各调性之间的差异较为适中，表明这些调性在流行度上较为均衡。


代码
# 找出平均播放量最高的前五个调性
top5_key &lt;- df |&gt;
  group_by(key) |&gt;
  summarize(mean_streams = mean(streams), .groups = "drop") |&gt;
  arrange(desc(mean_streams)) |&gt;
  head(5) |&gt;
  mutate(key = reorder(key, -mean_streams))  # 将 key 转换为因子




代码
# 条形图
plot_ly(
  top5_key, x = ~key, y = ~mean_streams, type = "bar",
  marker = list(color = "mediumaquamarine")
) |&gt;
  layout(
    title = list(y = 0.9, text = "最受欢迎的前五个调性"),
    xaxis = list(title = "调性", linewidth = 2, range = c(-0.8, 4.8)),
    yaxis = list(title = list(text = "平均播放量", standoff = 10)),
    margin = list(t = 80, l = 80, r = 20)
  )

